import{_ as i,o as r,c as t,ag as n}from"./chunks/framework.DTiDeF2Q.js";const h=JSON.parse('{"title":"Pfade (Paths) | Dotfiles (DE)","titleTemplate":":title","description":"Wie Dotfiles Ihre \\\\$PATH-Hierarchie verwaltet, um sicherzustellen, dass die richtigen Tools in der richtigen Reihenfolge geladen werden.","frontmatter":{"title":"Pfade (Paths) | Dotfiles","description":"Wie Dotfiles Ihre \\\\$PATH-Hierarchie verwaltet, um sicherzustellen, dass die richtigen Tools in der richtigen Reihenfolge geladen werden.","lang":"de-DE","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Pfade (Paths) preview","canonical":"/de/paths/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Pfade (Paths)","pageType":"docs","schemaType":"WebPage","metaTitle":"Pfade (Paths) - Dotfiles (DE)","permalink":"/de/paths/","meta":[{"name":"keywords","content":"pfad, umgebung, variablen, hierarchie, dotfiles, chezmoi"}]},"headers":[],"relativePath":"de/paths/index.md","filePath":"de/paths/index.md","lastUpdated":1773010926000}'),o={name:"de/paths/index.md"};function a(s,e,l,d,g,c){return r(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="pfadverwaltung" tabindex="-1">Pfadverwaltung <a class="header-anchor" href="#pfadverwaltung" aria-label="Permalink to &quot;Pfadverwaltung&quot;">​</a></h1><p>Eine der kritischsten Aufgaben von Dotfiles ist die Verwaltung Ihrer <code>$PATH</code>-Umgebungsvariablen. Dies bestimmt, welche Version eines Tools ausgeführt wird, wenn Sie einen Befehl eingeben.</p><p>Wir halten uns an eine strikte Hierarchie, um Konsistenz zwischen macOS und Linux zu gewährleisten.</p><h2 id="die-hierarchie" tabindex="-1">Die Hierarchie <a class="header-anchor" href="#die-hierarchie" aria-label="Permalink to &quot;Die Hierarchie&quot;">​</a></h2><p>Von höchster Priorität (zuerst geprüft) bis zur niedrigsten:</p><ol><li><p><strong>Lokale Binärdateien</strong> (<code>~/.local/bin</code>)</p><ul><li><strong>Priorität</strong>: 1</li><li><strong>Zweck</strong>: Benutzerdefinierte Benutzerskripte, <code>dot</code>-CLI und Tools, die über <code>pipx</code> oder andere Paketmanager auf Benutzerebene installiert wurden.</li><li><strong>Grund</strong>: Ermöglicht es Ihnen, System- oder Homebrew-Tools mit Ihren eigenen Versionen zu überschreiben.</li></ul></li><li><p><strong>Anwendungs-Binärdateien</strong> (macOS)</p><ul><li><strong>Priorität</strong>: 2</li><li><strong>Zweck</strong>: Binärdateien von installierten Anwendungen (z. B. VS Code, iTerm).</li></ul></li><li><p><strong>Sprach-Laufzeiten</strong></p><ul><li><strong>Node.js</strong>: <code>~/.node_modules/bin</code></li><li><strong>Go</strong>: <code>~/go/bin</code></li><li><strong>Rust (Cargo)</strong>: <code>~/.cargo/bin</code></li><li><strong>Ruby (User Gems)</strong>: <code>~/.gem/ruby/bin</code></li><li><strong>Python (Pipx)</strong>: <code>~/.local/share/pipx</code></li></ul></li><li><p><strong>Homebrew</strong> (<code>/opt/homebrew/bin</code>)</p><ul><li><strong>Priorität</strong>: 3</li><li><strong>Zweck</strong>: Hauptpaketmanager für macOS/Linux.</li><li><strong>Hinweis</strong>: Wir laden Homebrew absichtlich <em>vor</em> den Systempfaden, um das Upgrade von Systemwerkzeugen (wie <code>git</code> oder <code>curl</code>) zu ermöglichen.</li></ul></li><li><p><strong>Systempfade</strong> (<code>/usr/bin</code>, <code>/bin</code>)</p><ul><li><strong>Priorität</strong>: Niedrigste</li><li><strong>Zweck</strong>: Standard-Betriebssystemwerkzeuge.</li><li><strong>Grund</strong>: Rückfalloption für grundlegende Dienstprogramme.</li></ul></li></ol><h2 id="deduplizierung" tabindex="-1">Deduplizierung <a class="header-anchor" href="#deduplizierung" aria-label="Permalink to &quot;Deduplizierung&quot;">​</a></h2><p>Dotfiles dedupliziert Ihren <code>$PATH</code> automatisch, während die Rangfolge beibehalten wird. Dies verhindert, dass die <code>$PATH</code>-Variable beim Starten verschachtelter Shells unbegrenzt wächst.</p>',8)])])}const p=i(o,[["render",a]]);export{h as __pageData,p as default};
